// ═══════════════════════════════════════════════════════════════════
// 📂 Read Library - AI Factory v6
// ═══════════════════════════════════════════════════════════════════

const fs = require('fs');
const path = require('path');

const root = $('⚙️ CONFIG').first().json.root_path;

function parseYamlV6(content) {
  const lines = content.split(/\r?\n/);
  const result = {};

  let i = 0;
  while (i < lines.length) {
    const line = lines[i];
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith('#')) { i++; continue; }

    const indent = line.search(/\S/);

    if (indent === 0 && trimmed.endsWith(':') && !trimmed.includes(' ')) {
      const topKey = trimmed.slice(0, -1);
      if (topKey.startsWith('_')) { i++; continue; }

      i++;
      const obj = parseBlock(lines, i, 2);
      result[topKey] = obj.value;
      i = obj.nextLine;
      continue;
    }
    i++;
  }
  return result;
}

function parseBlock(lines, startLine, baseIndent) {
  const obj = {};
  let i = startLine;
  while (i < lines.length) {
    const line = lines[i];
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith('#')) { i++; continue; }

    const indent = line.search(/\S/);
    if (indent < baseIndent) break;
    if (indent > baseIndent) { i++; continue; }

    if (trimmed.includes(':')) {
      const colonIdx = trimmed.indexOf(':');
      const key = trimmed.slice(0, colonIdx).trim();
      const rawVal = trimmed.slice(colonIdx + 1).trim();

      if (key === 'loras' && (rawVal === '' || rawVal === null)) {
        const arr = parseLoras(lines, i + 1, baseIndent + 2);
        obj.loras = arr.value;
        i = arr.nextLine;
        continue;
      }

      if (rawVal === '' || rawVal === null) {
        i++;
        const nested = parseBlock(lines, i, baseIndent + 2);
        obj[key] = nested.value;
        i = nested.nextLine;
        continue;
      }

      obj[key] = parseValue(rawVal);
      i++;
      continue;
    }
    i++;
  }
  return { value: obj, nextLine: i };
}

function parseLoras(lines, startLine, baseIndent) {
  const arr = [];
  let i = startLine;
  while (i < lines.length) {
    const line = lines[i];
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith('#')) { i++; continue; }
    const indent = line.search(/\S/);
    if (indent < baseIndent) break;

    if (trimmed.startsWith('- file:')) {
      const lora = { file: parseValue(trimmed.split(':').slice(1).join(':').trim()) };
      i++;
      while (i < lines.length) {
        const subLine = lines[i];
        const subTrimmed = subLine.trim();
        if (!subTrimmed || subTrimmed.startsWith('#')) { i++; continue; }
        const subIndent = subLine.search(/\S/);
        if (subIndent <= baseIndent || subTrimmed.startsWith('- ')) break;
        if (subTrimmed.includes(':')) {
          const cIdx = subTrimmed.indexOf(':');
          const k = subTrimmed.slice(0, cIdx).trim();
          const v = subTrimmed.slice(cIdx + 1).trim();
          lora[k] = parseValue(v);
        }
        i++;
      }
      arr.push(lora);
      continue;
    }
    i++;
  }
  return { value: arr, nextLine: i };
}

function parseValue(val) {
  if (val === undefined || val === null) return null;
  val = String(val).trim().replace(/^"|"$/g, '').replace(/^'|'$/g, '');
  if (val === '' || val === 'null') return null;
  if (val === 'true') return true;
  if (val === 'false') return false;
  if (!isNaN(parseFloat(val)) && !val.includes(' ') && !val.includes(',')) return parseFloat(val);
  return val;
}

function readLibraryFolder(folderPath) {
  const combined = {};
  if (!fs.existsSync(folderPath)) return combined;
  const entries = fs.readdirSync(folderPath, { withFileTypes: true });
  entries.forEach(entry => {
    const fullPath = path.join(folderPath, entry.name);
    if (entry.isDirectory()) {
      Object.assign(combined, readLibraryFolder(fullPath));
    } else if (entry.name.endsWith('.yaml')) {
      const content = fs.readFileSync(fullPath, 'utf8');
      const parsed = parseYamlV6(content);
      Object.assign(combined, parsed);
    }
  });
  return combined;
}

const baseModelPath = path.join(root, 'library', 'base_model.yaml');
const baseModelContent = fs.readFileSync(baseModelPath, 'utf8');

let checkpoint = 'illustriousXL.safetensors';
let settings = { width: 832, height: 1216, steps: 28, cfg: 4, clip_skip: 2, sampler: 'euler_ancestral', scheduler: 'normal' };
let qualityPositive = '';
let qualityNegative = '';

const checkpointMatch = baseModelContent.match(/^checkpoint:\s*["']?([^"'\n]+)["']?/m);
if (checkpointMatch) checkpoint = checkpointMatch[1].trim();
['width', 'height', 'steps', 'cfg', 'clip_skip'].forEach(key => {
  const match = baseModelContent.match(new RegExp('^\\s+' + key + ':\\s*([\\d.]+)', 'm'));
  if (match) settings[key] = parseFloat(match[1]);
});
const samplerMatch = baseModelContent.match(/^\s+sampler:\s*["']?([^"'\n]+)["']?/m);
if (samplerMatch) settings.sampler = samplerMatch[1].trim();
const schedulerMatch = baseModelContent.match(/^\s+scheduler:\s*["']?([^"'\n]+)["']?/m);
if (schedulerMatch) settings.scheduler = schedulerMatch[1].trim();

const posMatch = baseModelContent.match(/^positive:\s*["']?([^"'\n]+)["']?/m);
if (posMatch) qualityPositive = posMatch[1].trim();
const negMatch = baseModelContent.match(/^negative:\s*["']?([^"'\n]+)["']?/m);
if (negMatch) qualityNegative = negMatch[1].trim();

const library = {
  styles: readLibraryFolder(path.join(root, 'library', 'styles')),
  cameras: readLibraryFolder(path.join(root, 'library', 'cameras')),
  characters: readLibraryFolder(path.join(root, 'library', 'characters')),
  outfits: readLibraryFolder(path.join(root, 'library', 'outfits')),
  poses: readLibraryFolder(path.join(root, 'library', 'poses')),
  expressions: readLibraryFolder(path.join(root, 'library', 'expressions')),
  backgrounds: readLibraryFolder(path.join(root, 'library', 'backgrounds'))
};

const jobPath = path.join(root, 'queue', 'job.yaml');
const jobContent = fs.readFileSync(jobPath, 'utf8');

let presetMode = false;
let presetFile = '';
let draftsPerCombination = 2;
let jobs = [];

const presetModeMatch = jobContent.match(/^preset_mode:\s*(true|false)/m);
if (presetModeMatch) presetMode = presetModeMatch[1] === 'true';

const presetFileMatch = jobContent.match(/^preset_file:\s*["']?([^"'\n]+)["']?/m);
if (presetFileMatch) presetFile = presetFileMatch[1].trim();

const draftsMatch = jobContent.match(/drafts_per_combination:\s*(\d+)/m);
if (draftsMatch) draftsPerCombination = parseInt(draftsMatch[1]);

function parseArrayOrValue(str) {
  if (!str) return [null];
  str = String(str).trim();
  if (str.startsWith('[')) {
    return str.slice(1, -1).split(',').map(s => s.trim()).filter(Boolean);
  }
  return [str];
}

function cartesian(arrays) {
  return arrays.reduce((acc, arr) => acc.flatMap(x => arr.map(y => [...x, y])), [[]]);
}

if (!presetMode) {
  const jobsSection = jobContent.split('jobs:')[1];
  if (jobsSection) {
    let currentJob = null;
    let rawJobs = [];
    jobsSection.split(/\r?\n/).forEach(line => {
      const trimmed = line.trim();
      if (trimmed.startsWith('#')) return;
      if (trimmed.startsWith('- ') && trimmed.includes(':')) {
        if (currentJob) rawJobs.push(currentJob);
        currentJob = {};
        const rest = trimmed.slice(2);
        const colonIdx = rest.indexOf(':');
        const key = rest.slice(0, colonIdx).trim();
        const val = rest.slice(colonIdx + 1).trim();
        currentJob[key] = val;
      } else if (currentJob && trimmed.includes(':') && !trimmed.startsWith('#')) {
        const colonIdx = trimmed.indexOf(':');
        const key = trimmed.slice(0, colonIdx).trim();
        const val = trimmed.slice(colonIdx + 1).trim();
        currentJob[key] = val;
      }
    });
    if (currentJob) rawJobs.push(currentJob);

    const jobKeys = ['style', 'camera', 'outfit', 'pose', 'expression', 'background'];
    rawJobs.forEach(rawJob => {
      const arrays = {};
      arrays.character = parseArrayOrValue(rawJob.character);
      jobKeys.forEach(key => { arrays[key] = parseArrayOrValue(rawJob[key]); });
      const allKeys = ['character', ...jobKeys];
      const allArrays = allKeys.map(k => arrays[k]);
      const combinations = cartesian(allArrays);
      combinations.forEach(combo => {
        const job = {};
        allKeys.forEach((key, i) => { job[key] = combo[i]; });
        jobs.push(job);
      });
    });
  }
}

if (presetMode && presetFile) {
  const presetPath = path.join(root, 'presets', presetFile);
  const presetContent = fs.readFileSync(presetPath, 'utf8');
  const fixed = {};
  const fixedSection = presetContent.match(/fixed:[\s\S]*?(?=variants:|settings:|$)/);
  if (fixedSection) {
    fixedSection[0].split(/\r?\n/).forEach(line => {
      if (line.includes(':') && !line.trim().startsWith('#') && line.trim() !== 'fixed:') {
        const [key, ...val] = line.trim().split(':');
        fixed[key.trim()] = val.join(':').trim();
      }
    });
  }
  const variants = {};
  const variantsSection = presetContent.match(/variants:[\s\S]*?(?=settings:|$)/);
  if (variantsSection) {
    variantsSection[0].split(/\r?\n/).forEach(line => {
      const trimmed = line.trim();
      if (trimmed.includes(':') && !trimmed.startsWith('#') && trimmed !== 'variants:') {
        const colonIdx = trimmed.indexOf(':');
        const key = trimmed.slice(0, colonIdx).trim();
        const val = trimmed.slice(colonIdx + 1).trim();
        if (val.startsWith('[')) {
          variants[key] = val.slice(1, -1).split(',').map(s => s.trim()).filter(Boolean);
        }
      }
    });
  }
  const settingsMatch = presetContent.match(/drafts_per_combination:\s*(\d+)/);
  if (settingsMatch) draftsPerCombination = parseInt(settingsMatch[1]);
  const keys = Object.keys(variants);
  const variantArrays = keys.map(k => variants[k].length > 0 ? variants[k] : [null]);
  const combinations = cartesian(variantArrays);
  combinations.forEach(combo => {
    const job = { ...fixed };
    keys.forEach((key, i) => {
      if (combo[i]) {
        let singularKey = key;
        if (key === 'cameras') singularKey = 'camera';
        else if (key.endsWith('s')) singularKey = key.slice(0, -1);
        job[singularKey] = combo[i];
      }
    });
    jobs.push(job);
  });
}

return {
  json: {
    checkpoint, settings, quality_positive: qualityPositive, quality_negative: qualityNegative, library, jobs, drafts_per_combination: draftsPerCombination
  }
};

// 🎯 FLATTEN TASKS
const data = $input.first().json;
const allTasks = [];
let taskIndex = 0;

for (const job of data.jobs) {
  for (let draft = 1; draft <= data.drafts_per_combination; draft++) {
    taskIndex++;
    const style = data.library.styles[job.style] || {};
    const camera = data.library.cameras[job.camera] || {};
    const character = data.library.characters[job.character] || {};
    const pose = data.library.poses[job.pose] || {};
    const expression = data.library.expressions[job.expression] || {};
    const background = data.library.backgrounds[job.background] || {};
    let outfit = {};
    let outfitId = job.outfit || 'default';
    if (outfitId === 'default' || outfitId === null) {
      outfit = character.default_outfit || {};
      outfitId = 'default';
    } else if (outfitId === 'none') {
      outfit = {};
      outfitId = 'none';
    } else {
      outfit = data.library.outfits[outfitId] || {};
    }
    allTasks.push({
      json: {
        task_index: taskIndex,
        total_tasks: 0,
        draft_index: draft,
        seed: Math.floor(Math.random() * 10000000000),
        checkpoint: data.checkpoint,
        settings: data.settings,
        quality_positive: data.quality_positive,
        quality_negative: data.quality_negative,
        ids: {
          style: job.style || 'default',
          character: job.character || 'unknown',
          camera: job.camera || 'front',
          outfit: outfitId,
          pose: job.pose || 'standing',
          expression: job.expression || 'neutral',
          background: job.background || 'simple'
        },
        data: { style, camera, character, outfit, pose, expression, background }
      }
    });
  }
}
allTasks.forEach(t => t.json.total_tasks = allTasks.length);
return allTasks;

const task = $input.first().json;
const d = task.data;
const positiveParts = [];
const negativeParts = [];
const loraStack = [];

function addPositive(text) { if (text && text !== 'null') positiveParts.push(String(text).trim()); }
function addNegative(text) { if (text && text !== 'null') negativeParts.push(String(text).trim()); }
function addLora(file, strength, type) {
  if (!file) return;
  loraStack.push({ name: file.replace('.safetensors', ''), file, strength: strength || 0.7, type });
}
function addComponentLora(component, type) {
  if (component && component.lora && component.lora.file) addLora(component.lora.file, component.lora.strength, type);
}

addPositive(task.quality_positive);
addNegative(task.quality_negative);

if (d.style) {
  if (d.style.loras) d.style.loras.forEach(l => { if (l.file) { addLora(l.file, l.strength, 'style'); addPositive(l.positive); addNegative(l.negative); } });
  if (d.style.body) { addPositive(d.style.body.positive); addNegative(d.style.body.negative); if (d.style.body.lora) addLora(d.style.body.lora.file, d.style.body.lora.strength, 'body'); }
  addPositive(d.style.positive); addNegative(d.style.negative);
}

if (d.camera) { addPositive(d.camera.positive); addNegative(d.camera.negative); addComponentLora(d.camera, 'camera'); }
if (d.character) {
  if (d.character.lora) addLora(d.character.lora.file, d.character.lora.strength, 'character');
  if (d.character.positive) addPositive(`(${d.character.positive})`);
  addNegative(d.character.negative);
  if (d.character.appearance) { addPositive(d.character.appearance.positive); addNegative(d.character.appearance.negative); }
}
if (d.outfit) { addPositive(d.outfit.positive); addNegative(d.outfit.negative); addComponentLora(d.outfit, 'outfit'); }
if (d.pose) { addPositive(d.pose.positive); addNegative(d.pose.negative); addComponentLora(d.pose, 'pose'); }
if (d.expression) { addPositive(d.expression.positive); addNegative(d.expression.negative); addComponentLora(d.expression, 'expression'); }
if (d.background) { addPositive(d.background.positive); addNegative(d.background.negative); addComponentLora(d.background, 'background'); }

const finalPos = positiveParts.filter(Boolean).join(', ');
return {
  json: { ...task, final_positive: finalPos, final_negative: negativeParts.filter(Boolean).join(', '), lora_stack: loraStack }
};

const task = $input.first().json;
const s = task.settings || {};
const uid = task.seed.toString().slice(-4);
function fix(n) { return n && (n.endsWith('.safetensors') ? n : n + '.safetensors'); }
const workflow = {};
const ckptId = uid + '_ckpt';
workflow[ckptId] = { 'class_type': 'CheckpointLoaderSimple', 'inputs': { 'ckpt_name': fix(task.checkpoint) } };
let lastM = [ckptId, 0], lastC = [ckptId, 1], count = 1;
(task.lora_stack || []).forEach(l => {
  const id = uid + '_lora' + (count++);
  workflow[id] = { 'class_type': 'LoraLoader', 'inputs': { 'lora_name': fix(l.name), 'strength_model': l.strength || 1, 'strength_clip': l.strength || 1, 'model': lastM, 'clip': lastC } };
  lastM = [id, 0]; lastC = [id, 1];
});
const csId = uid + '_clip';
workflow[csId] = { 'class_type': 'CLIPSetLastLayer', 'inputs': { 'stop_at_clip_layer': -(s.clip_skip || 2), 'clip': lastC } };
const posId = uid + '_pos', negId = uid + '_neg';
workflow[posId] = { 'class_type': 'CLIPTextEncode', 'inputs': { 'text': task.final_positive, 'clip': [csId, 0] } };
workflow[negId] = { 'class_type': 'CLIPTextEncode', 'inputs': { 'text': task.final_negative, 'clip': [csId, 0] } };
const latId = uid + '_lat';
workflow[latId] = { 'class_type': 'EmptyLatentImage', 'inputs': { 'width': s.width || 832, 'height': s.height || 1216, 'batch_size': 1 } };
const samId = uid + '_sam';
workflow[samId] = { 'class_type': 'KSampler', 'inputs': { 'seed': task.seed, 'steps': s.steps || 25, 'cfg': s.cfg || 5, 'sampler_name': s.sampler || 'euler', 'scheduler': s.scheduler || 'normal', 'denoise': 1, 'model': lastM, 'positive': [posId, 0], 'negative': [negId, 0], 'latent_image': [latId, 0] } };
const vaeId = uid + '_vae';
workflow[vaeId] = { 'class_type': 'VAEDecode', 'inputs': { 'samples': [samId, 0], 'vae': [ckptId, 2] } };
const savId = uid + '_sav';
workflow[savId] = { 'class_type': 'SaveImage', 'inputs': { 'filename_prefix': 'AIFactory_', 'images': [vaeId, 0] } };
return { json: { prompt: workflow, task } };

const fs = require('fs');
const path = require('path');
const config = $('⚙️ CONFIG').first().json;
const task = $('🔧 Build ComfyUI').first().json.task;
const history = $input.first().json;
const promptId = Object.keys(history)[0];
const outputs = history[promptId]?.outputs || {};
let image = null;
for (const key in outputs) { if (outputs[key].images) { image = outputs[key].images[0]; break; } }
if (!image) throw new Error('No image');
const sourceFile = path.join(config.comfy_path, 'output', image.subfolder || '', image.filename);
const clean = s => (s || 'unknown').replace(/[^a-zA-Z0-9_-]/g, '_').substring(0, 30);
const outDir = path.join(config.root_path, 'output', clean(task.ids.style), clean(task.ids.character));
if (!fs.existsSync(outDir)) fs.mkdirSync(outDir, { recursive: true });
const filename = [String(task.task_index).padStart(3, '0'), clean(task.ids.pose), clean(task.ids.camera), clean(task.ids.outfit), task.seed].join('_');
fs.copyFileSync(sourceFile, path.join(outDir, filename + '.png'));

function yamlStr(val, indent = '') {
  if (val === null || val === undefined) return 'null';
  if (Array.isArray(val)) return '\n' + val.map(v => `${indent}  - ${yamlStr(v, indent + '  ')}`).join('\n');
  if (typeof val === 'object') return '\n' + Object.keys(val).map(k => `${indent}  ${k}: ${yamlStr(val[k], indent + '  ')}`).join('\n');
  return String(val);
}

const yamlContent = `# AI Factory v6\ngenerated: "${new Date().toISOString()}"\nseed: ${task.seed}\nids: ${yamlStr(task.ids)}\nprompt:\n  positive: "${task.final_positive}"\n  negative: "${task.final_negative}"\nsource_data: ${yamlStr(task.data)}`;
fs.writeFileSync(path.join(outDir, filename + '.yaml'), yamlContent);
return { json: { success: true, file: filename } };
